/**
 * fetchModel - Fetch a model from the web server.
 *
 * @param {string} url      The URL to issue the GET request.
 * @returns {Promise}       A Promise that resolves with the response data.
 */
function fetchModel(url) {
  // 1. Thêm link Backend của bạn vào đây
  const backendBaseUrl = "http://localhost:8081";

  // 2. Nếu url bắt đầu bằng "/", ta ghép nó với link backend
  const fullUrl = url.startsWith("/") ? backendBaseUrl + url : url;

  return new Promise(function (resolve, reject) {
    // 3. Truyền fullUrl vào hàm fetch thay vì url cũ
    fetch(fullUrl)
      .then(function (response) {
        if (!response.ok) {
          throw new Error(
            "Lỗi HTTP: " + response.status + " " + response.statusText
          );
        }
        return response.json();
      })
      .then(function (data) {
        resolve({ data: data });
      })
      .catch(function (error) {
        console.error("Lỗi khi fetch data từ URL:", fullUrl, error);
        reject(error);
      });
  });
}

export default fetchModel;
